patch:
diff --git a/llvm/lib/Transforms/Utils/LoopPeel.cpp b/llvm/lib/Transforms/Utils/LoopPeel.cpp
index c5c637ab6e20..a3786e06ec08 100644
--- a/llvm/lib/Transforms/Utils/LoopPeel.cpp
+++ b/llvm/lib/Transforms/Utils/LoopPeel.cpp
@@ -1077,8 +1077,14 @@ bool llvm::peelLoop(Loop *L, unsigned PeelCount, bool PeelLast, LoopInfo *LI,
     // Exit:
     // ...
     BasicBlock *Exit = L->getExitBlock();
-    for (PHINode &P : Exit->phis())
-      ExitValues[&P] = P.getIncomingValueForBlock(Latch);
+    for (PHINode &P : Exit->phis()) {
+      Value *E = P.getIncomingValueForBlock(Latch);
+      if (isa<Constant>(E)) {
+        P.replaceAllUsesWith(E);
+        continue;
+      }
+      ExitValues[&P] = E;
+    }

     InsertTop = SplitEdge(Latch, Exit, &DT, LI);
     InsertBot = SplitBlock(InsertTop, InsertTop->getTerminator(), &DT, LI);

